 1	import { Card } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { NetflowMetrics, Stats } from '../../api/loki';
 4	import { Warning } from '../../model/warnings';
 5	import { MetricsQuerySummaryContent } from './metrics-query-summary-content';
 6	import './query-summary.css';
 7	
 8	export interface MetricsQuerySummaryProps {
 9	  stats?: Stats;
10	  metrics: NetflowMetrics;
11	  loading?: boolean;
12	  lastRefresh?: Date;
13	  lastDuration?: number;
14	  warning?: Warning;
15	  isShowQuerySummary?: boolean;
16	  toggleQuerySummary?: () => void;
17	  isDark?: boolean;
18	}
19	
20	export const MetricsQuerySummary: React.FC<MetricsQuerySummaryProps> = ({
21	  metrics,
22	  stats,
23	  loading,
24	  lastRefresh,
25	  lastDuration,
26	  warning,
27	  isShowQuerySummary,
28	  toggleQuerySummary,
29	  isDark
30	}) => {
31	  return (
32	    <Card id="query-summary">
33	      <MetricsQuerySummaryContent
34	        className="summary-container"
35	        direction="row"
36	        metrics={metrics}
37	        numQueries={stats?.numQueries}
38	        dataSources={stats?.dataSources}
39	        loading={loading}
40	        lastRefresh={lastRefresh}
41	        lastDuration={lastDuration}
42	        warning={warning}
43	        isShowQuerySummary={isShowQuerySummary}
44	        toggleQuerySummary={toggleQuerySummary}
45	        isDark={isDark}
46	      />
47	    </Card>
48	  );
49	};
50	
51	export default MetricsQuerySummary;

