 1	import { render, waitFor } from '@testing-library/react';
 2	import userEvent from '@testing-library/user-event';
 3	import * as React from 'react';
 4	
 5	import { defaultNetflowMetrics, NetflowMetrics } from '../../../api/loki';
 6	import { Result } from '../../../utils/result';
 7	import { metrics } from '../../__tests-data__/metrics';
 8	import { MetricsQuerySummary } from '../metrics-query-summary';
 9	
10	describe('<MetricsQuerySummary />', () => {
11	  const now = new Date();
12	
13	  const m: NetflowMetrics = { ...defaultNetflowMetrics, rate: Result.success({ bytes: metrics }) };
14	  const mocks = {
15	    toggleQuerySummary: jest.fn(),
16	    metrics: m,
17	    stats: {
18	      limitReached: false,
19	      numQueries: 1,
20	      dataSources: ['loki']
21	    },
22	    lastRefresh: now
23	  };
24	
25	  it('should render component', async () => {
26	    const { container } = render(<MetricsQuerySummary {...mocks} />);
27	    await waitFor(() => {
28	      expect(container.querySelector('#query-summary-content')).toBeTruthy();
29	    });
30	  });
31	
32	  it('should show summary', async () => {
33	    const { container } = render(<MetricsQuerySummary {...mocks} />);
34	    await waitFor(() => {
35	      expect(container.querySelector('#bytesCount')).toBeTruthy();
36	    });
37	
38	    expect(container.querySelector('#bytesCount')?.textContent).toBe('6.8 MB');
39	    expect(container.querySelector('#packetsCount')).toBeNull();
40	    expect(container.querySelector('#bytesPerSecondsCount')?.textContent).toBe('22.79 kBps');
41	    expect(container.querySelector('#lastRefresh')?.textContent).toBe(now.toLocaleTimeString());
42	  });
43	
44	  it('should toggle panel', async () => {
45	    const user = userEvent.setup();
46	    const { container } = render(<MetricsQuerySummary {...mocks} />);
47	    await waitFor(() => {
48	      expect(container.querySelector('#query-summary-toggle')).toBeTruthy();
49	    });
50	
51	    await user.click(container.querySelector('#query-summary-toggle')!);
52	    expect(mocks.toggleQuerySummary).toHaveBeenCalledTimes(1);
53	  });
54	});

